            addFault(faults, field, "INVALID");
            return;
        }
        if (isNum(opts.min) && out[field] < opts.min) addFault(faults, field, "INVALID");
        if (isNum(opts.max) && out[field] > opts.max) addFault(faults, field, "INVALID");
    }

    function requireBool(field, opts) {
        opts = opts || {};
        let installKey = opts.installKey || null;
        if (installKey && !installed(hw, installKey)) {
            addFault(faults, field, "NOT INSTALLED");
            return;
        }
        if (!(field in out) || out[field] === null || out[field] === "") {
            addFault(faults, field, "MISSING");
